#include <iostream>
#include <cstring>

class MyString {
private:
    char* data;
    size_t len;

public:
    MyString() : data(nullptr), len(0) {
        data = new char[1];
        data[0] = '\0';
    }

    MyString(const char* s) {
        len = std::strlen(s);
        data = new char[len + 1];
        std::strcpy(data, s);
    }

    MyString(const MyString& other) : len(other.len) {
        data = new char[len + 1];
        std::strcpy(data, other.data);
    }

    ~MyString() {
        delete[] data;
    }

    void display() const {
        std::cout << data;
    }

    size_t getLength() const {
        std::cout << len;
    }
};

int main() {
    MyString s1("Hello");
    std::cout << "s1: ";
    s1.display();
    std::cout << " (Length: "; s1.getLength(); std::cout << ")\n";

    MyString s2 = s1;
    std::cout << "s2 (copy of s1): ";
    s2.display();
    std::cout << " (Length: "; s2.getLength(); std::cout << ")\n";

    MyString s3("World");
    std::cout << "s3: ";
    s3.display();
    std::cout << " (Length: "; s3.getLength(); std::cout << ")\n";

    MyString s4("");
    std::cout << "s4 (empty): ";
    s4.display();
    std::cout << " (Length: "; s4.getLength(); std::cout << ")\n";

    std::cout << "Attempting to create MyString from nullptr...\n";
    // This will cause a runtime crash due to strlen(nullptr)
    MyString s5(nullptr); 
    std::cout << "s5: ";
    s5.display();
    std::cout << " (Length: "; s5.getLength(); std::cout << ")\n";

    return 0;
}
